test('registers and emits events', async () => {
  const emitter = new EventEmitter();
  let value = 0;
  emitter.on('increment', (n: number) => { value += n; });
  await emitter.emit('increment', 5);
  expect(value).toBe(5);
});

test('removes listeners', async () => {
  const emitter = new EventEmitter();
  let calls = 0;
  const listener = () => { calls++; };
  emitter.on('test', listener);
  await emitter.emit('test');
  emitter.off('test', listener);
  await emitter.emit('test');
  expect(calls).toBe(1);
});

test('handles listener errors gracefully', async () => {
  const emitter = new EventEmitter();
  let calls = 0;
  emitter.on('test', () => { throw new Error('boom'); });
  emitter.on('test', () => { calls++; });
  await emitter.emit('test');
  expect(calls).toBe(1);
});

test('supports async listeners', async () => {
  const emitter = new EventEmitter();
  let result = '';
  emitter.on('load', async () => {
    await new Promise(resolve => setTimeout(resolve, 10));
    result += 'async';
  });
  emitter.on('load', () => { result += '-sync'; });
  await emitter.emit('load');
  expect(result).toBe('async-sync');
});
